@using sv_e74238a887d741588cf93cf8fa87ff42.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row">
    @* ===== Left Sidebar (Filters) ===== *@
    <div class="pe-4" style="width: 25%; min-width: 220px;">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (_categories is not null)
                {
                    @foreach (var category in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                   checked="@(_selectedCategories.Contains(category))"
                                   @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading categories…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small mb-0">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_minPrice" @bind:event="oninput" placeholder="0" />
                </div>
                <div class="mb-2">
                    <label class="form-label small mb-0">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="_maxPrice" @bind:event="oninput" placeholder="Any" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ===== Main Content Area ===== *@
    <div style="width: 75%;">
        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_errorMessage
            </div>
        }
        else if (_isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary me-2" role="status"></div>
                <span>Loading products…</span>
            </div>
        }
        else if (_result is not null && _result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products match your filters. Try adjusting your criteria.
            </div>
        }
        else if (_result is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-1">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @bind="_sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))
                    of @_result.TotalCount products
                </span>
            </div>

            @* Product Grid *@
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-4">
                @foreach (var product in _result.Items)
                {
                    <div class="col">
                        <div class="card h-100 product-card" @onclick="() => OnProductSelected(product)"
                             style="cursor: pointer;">
                            <div class="bg-light d-flex align-items-center justify-content-center"
                                 style="height: 180px;">
                                <span class="text-muted" role="img" aria-label="@product.Name">@product.Name</span>
                            </div>
                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-1">
                                    @RenderStars(product.Rating)
                                </p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }" @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>

            @* Pagination *@
            @{
                var totalPages = (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
            }
            @if (totalPages > 1)
            {
                <nav aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                    disabled="@(_currentPage == 1)">Previous</button>
                        </li>
                        @for (var i = 1; i <= totalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                    disabled="@(_currentPage == totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter] public EventCallback<Product> OnProductClick { get; set; }

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? _result;
    private bool _isLoading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProducts();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
            _isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        _isLoading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task OnSortChanged()
    {
        _currentPage = 1;
        await SearchProducts();
    }

    private async Task GoToPage(int page)
    {
        _currentPage = page;
        await SearchProducts();
    }

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClick.HasDelegate)
            await OnProductClick.InvokeAsync(product);
    }

    private static string RenderStars(double rating)
    {
        var rounded = (int)Math.Round(rating);
        return new string('★', rounded) + new string('☆', 5 - rounded);
    }
}
"}

